    public TextDaemon(Path pluginJar, int workerCount) {
        this.revisions = new TimelineLedger(pluginJar);
        this.workers = Executors.newFixedThreadPool(workerCount, new WorkerThreadFactory());
        this.workerCount = workerCount;
